@import url("https://fonts.googleapis.com/css2?family=Figtree:wght@400;600;700&display=swap");
*, *::before, *::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

body {
  font-family: "Figtree", sans-serif;
  background: transparent;
  color: #05042E;
  font-size: 13px;
}

.wrap {
  padding: 16px;
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.survey-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.survey-title {
  font-size: 15px;
  font-weight: 700;
  color: #05042E;
}

.survey-sub {
  font-size: 11px;
  color: #888780;
  margin-top: 2px;
}

.adisa-badge {
  font-size: 10px;
  font-weight: 700;
  background: rgba(5, 4, 46, 0.06);
  color: #05042E;
  padding: 4px 10px;
  border-radius: 20px;
  border: 0.5px solid rgba(5, 4, 46, 0.15);
  letter-spacing: 0.03em;
}

.card {
  background: #fff;
  border: 0.5px solid rgba(0, 0, 0, 0.1);
  border-radius: 10px;
  overflow: hidden;
}

.card-section-title {
  font-size: 10px;
  font-weight: 700;
  color: #888780;
  text-transform: uppercase;
  letter-spacing: 0.06em;
  padding: 10px 14px;
  border-bottom: 0.5px solid rgba(0, 0, 0, 0.07);
  background: rgba(5, 4, 46, 0.02);
}

.section {
  padding: 14px;
  border-bottom: 0.5px solid rgba(0, 0, 0, 0.06);
}

.section:last-child {
  border-bottom: none;
}

.field-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 12px;
}

.field-group {
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.field-group.full {
  grid-column: 1/-1;
}

label {
  font-size: 10px;
  font-weight: 700;
  color: #888780;
  text-transform: uppercase;
  letter-spacing: 0.05em;
}

input[type=text], input[type=date], textarea, select {
  font-size: 13px;
  font-family: "Figtree", sans-serif;
  border: 0.5px solid rgba(0, 0, 0, 0.15);
  border-radius: 6px;
  padding: 7px 10px;
  color: #05042E;
  outline: none;
  width: 100%;
  background: #fff;
  transition: border-color 0.15s;
}

input:focus, textarea:focus, select:focus {
  border-color: #469BC0;
  box-shadow: 0 0 0 2px rgba(70, 155, 192, 0.08);
}

textarea {
  resize: vertical;
  min-height: 55px;
}

input::placeholder, textarea::placeholder {
  color: #c4c2be;
}

.toggle-row {
  display: flex;
  align-items: center;
  gap: 8px;
  margin-top: 2px;
}

.toggle {
  width: 38px;
  height: 20px;
  border-radius: 10px;
  border: none;
  cursor: pointer;
  position: relative;
  transition: background 0.2s;
  flex-shrink: 0;
}

.toggle.on {
  background: #A3E851;
}

.toggle.off {
  background: #E0DFE1;
}

.toggle-label {
  font-size: 12px;
  color: #888780;
  font-weight: 600;
}

.conditional {
  display: none;
  margin-top: 6px;
}

.conditional.show {
  display: block;
}

.form-actions {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 12px 0 0;
}

.review-note {
  font-size: 11px;
  color: #888780;
}

.review-note strong {
  color: #05042E;
}

.btn {
  font-size: 12px;
  font-weight: 700;
  padding: 8px 20px;
  border-radius: 6px;
  border: none;
  cursor: pointer;
  font-family: "Figtree", sans-serif;
  transition: all 0.15s;
}

.btn-primary {
  background: #A3E851;
  color: #05042E;
}

.btn-primary:hover {
  background: #8bc93d;
}

.btn-skip {
  background: transparent;
  color: #888780;
  text-decoration: underline;
  font-size: 12px;
  border: none;
  cursor: pointer;
  font-family: "Figtree", sans-serif;
}

.btn-skip:hover {
  color: #05042E;
}

